# --- Data Validation and Sanitization ---

class DataValidator:
    """Validates uploaded data to prevent poisoning attacks."""

    def __init__(self):
        self.reference_stats = None
        self._load_reference_stats()

    def _load_reference_stats(self):
        """Load reference statistics from trusted baseline dataset."""
        stats_path = 'reference_stats.npz'
        if os.path.exists(stats_path):
            data = np.load(stats_path)
            self.reference_stats = {
                'mean': data['mean'],
                'std': data['std'],
                'label_distribution': data['label_distribution'],
            }

    def save_reference_stats(self, images: np.ndarray, labels: np.ndarray):
        """Save reference statistics from a trusted baseline dataset."""
        self.reference_stats = {
            'mean': np.mean(images, axis=0),
            'std': np.std(images, axis=0),
            'label_distribution': np.bincount(labels, minlength=NUM_CLASSES) / len(labels),
        }
        np.savez('reference_stats.npz', **self.reference_stats)

    def validate_file(self, file) -> tuple[bool, str]:
        """Validate uploaded file format and basic properties."""
        filename = secure_filename(file.filename)
        if not filename:
            return False, "Invalid filename"

        ext = filename.rsplit('.', 1)[-1].lower() if '.' in filename else ''
        if ext not in ALLOWED_EXTENSIONS:
            return False, f"File type '{ext}' not allowed. Allowed: {ALLOWED_EXTENSIONS}"

        # Read file content for hash check
        content = file.read()
        file.seek(0)

        if len(content) == 0:
            return False, "Empty file"

        return True, "OK"

    def validate_csv_data(self, df: pd.DataFrame) -> tuple[bool, str, float]:
        """
        Validate CSV data for anomalies.
        Returns (is_valid, message, anomaly_score).
        """
        anomaly_score = 0.0

        # Check number of samples
        if len(df) > MAX_SAMPLES_PER_UPLOAD:
            return False, f"Too many samples ({len(df)}). Max: {MAX_SAMPLES_PER_UPLOAD}", 1.0

        if len(df) == 0:
            return False, "No samples in file", 1.0

        # Check for required columns
        if 'label' not in df.columns:
            return False, "Missing 'label' column", 1.0

        # Validate labels are integers within expected range
        labels = df['label'].values
        if not np.issubdtype(labels.dtype, np.integer):
            try:
                labels = labels.astype(int)
            except (ValueError, TypeError):
                return False, "Labels must be integers", 1.0

        if np.any(labels < FEATURE_BOUNDS['label_min']) or np.any(labels > FEATURE_BOUNDS['label_max']):
            return False, f"Labels out of range [{FEATURE_BOUNDS['label_min']}, {FEATURE_BOUNDS['label_max']}]", 1.0

        # Validate pixel/feature values
        feature_cols = [c for c in df.columns if c != 'label']
        if len(feature_cols) == 0:
            return False, "No feature columns found", 1.0

        features = df[feature_cols].values.astype(np.float32)

        # Check for NaN or Inf
        if np.any(np.isnan(features)) or np.any(np.isinf(features)):
            return False, "Data contains NaN or Inf values", 1.0

        # Check pixel value range
        if np.any(features < FEATURE_BOUNDS['pixel_min']) or np.any(features > FEATURE_BOUNDS['pixel_max']):
            return False, f"Feature values out of range [{FEATURE_BOUNDS['pixel_min']}, {FEATURE_BOUNDS['pixel_max']}]", 0.8

        # Statistical anomaly detection
        anomaly_score = self._compute_anomaly_score(features, labels)

        if anomaly_score > QUARANTINE_THRESHOLD:
            return True, f"Data flagged for review (anomaly_score={anomaly_score:.3f})", anomaly_score

        return True, "OK", anomaly_score

    def validate_image(self, image_data: bytes) -> tuple[bool, str]:
        """Validate a single image."""
        try:
            img = Image.open(io.BytesIO(image_data))
            # Verify it's a real image by loading pixel data
            img.verify()
            # Re-open after verify
            img = Image.open(io.BytesIO(image_data))
            img_array = np.array(img)

            # Check dimensions are reasonable
            if img_array.shape[0] < 8 or img_array.shape[1] < 8:
                return False, "Image too small"
            if img_array.shape[0] > 4096 or img_array.shape[1] > 4096:
                return False, "Image too large"

            # Check for adversarial patterns (e.g., single-color images, extreme noise)
            if np.std(img_array) < 1.0:
                return False, "Image appears to be single-color (likely not useful)"

            return True, "OK"
        except Exception as e:
            return False, f"Invalid image: {str(e)}"

    def _compute_anomaly_score(self, features: np.ndarray, labels: np.ndarray) -> float:
        """
        Compute anomaly score based on statistical deviation from reference data.
        Higher score = more anomalous.
        """
        scores = []

        # 1. Check label distribution skew
        label_dist = np.bincount(labels.astype(int), minlength=NUM_CLASSES) / len(labels)

        if self.reference_stats is not None:
            ref_dist = self.reference_stats['label_distribution']
            # KL divergence-like measure for label distribution
            epsilon = 1e-10
            kl_div = np.sum(label_dist * np.log((label_dist + epsilon) / (ref_dist + epsilon)))
            label_score = min(1.0, abs(kl_div) / 2.0)
            scores.append(label_score)

            # 2. Check feature distribution deviation
            batch_mean = np.mean(features, axis=0)
            ref_mean = self.reference_stats['mean'].flatten()[:len(batch_mean)]
            ref_std = self.reference_stats['std'].flatten()[:len(batch_mean)]

            if len(ref_mean) == len(batch_mean):
                # Z-score of batch mean relative to reference
                safe_std = np.where(ref_std > 0, ref_std, 1.0)
                z_scores = np.abs((batch_mean - ref_mean) / safe_std)
                mean_deviation_score = min(1.0, np.mean(z_scores) / 5.0)
                scores.append(mean_deviation_score)
        else:
            # Without reference stats, check for suspicious patterns
            # All same label
            if len(np.unique(labels)) == 1 and len(labels) > 10:
                scores.append(0.5)

            # Extremely uniform features (potential adversarial)
            feature_std = np.std(features, axis=0)
            if np.mean(feature_std) < 1.0:
                scores.append(0.6)

        # 3. Check for duplicate samples (potential amplification attack)
        unique_hashes = set()
        for row in features:
            row_hash = hashlib.md5(row.tobytes()).hexdigest()
            unique_hashes.add(row_hash)
        duplicate_ratio = 1.0 - len(unique_hashes) / len(features)
        if duplicate_ratio > 0.5:
            scores.append(0.7)

        # 4. Check for outlier samples using simple z-score
        global_mean = np.mean(features)
        global_std = np.std(features)
        if global_std > 0:
            z_scores = np.abs((features - global_mean) / global_std)
            outlier_ratio = np.mean(z_scores > 3.0)
            if outlier_ratio > 0.1:
                scores.append(min(1.0, outlier_ratio * 2))

        if not scores:
            return 0.0

        return float(np.mean(scores))

    def validate_label_consistency(self, features: np.ndarray, labels: np.ndarray,
                                    model: Optional[tf.keras.Model] = None) -> tuple[np.ndarray, float]:
        """
        Check if labels are consistent with existing model predictions.
        Returns mask of suspicious samples and overall inconsistency score.
        """
        if model is None:
            return np.ones(len(labels), dtype=bool), 0.0

        try:
            # Reshape features for model prediction
            img_size = int(np.sqrt(features.shape[1]))
            if img_size * img_size != features.shape[1]:
                # Can't reshape, skip this check
                return np.ones(len(labels), dtype=bool), 0.0

            images = features.reshape(-1, img_size, img_size, 1) / 255.0
            # Resize to model input size
            images_resized = tf.image.resize(images, IMAGE_SIZE).numpy()

            predictions = model.predict(images_resized, verbose=0)
            predicted_labels = np.argmax(predictions, axis=1)
            prediction_confidence = np.max(predictions, axis=1)

            # Flag samples where model is confident but label disagrees
            confident_mask = prediction_confidence > 0.8
            disagreement_mask = predicted_labels != labels.astype(int)
            suspicious = confident_mask & disagreement_mask

            inconsistency_score = np.mean(suspicious) if len(suspicious) > 0 else 0.0

            # Samples that are NOT suspicious are considered clean
            clean_mask = ~suspicious

            return clean_mask, float(inconsistency_score)
        except Exception as e:
            logger.warning(f"Label consistency check failed: {e}")
            return np.ones(len(labels), dtype=bool), 0.0


class RateLimiter:
    """Rate limiting for uploads per user."""

    @staticmethod
    def check_rate_limit(user_id: str, db) -> tuple[bool, str]:
        """Check if user has exceeded upload rate limit."""
        cursor = db.execute(
            '''SELECT COUNT(*) as cnt FROM upload_rate_limits
               WHERE user_id = ? AND upload_time > datetime('now', '-1 hour')''',
            (user_id,)
        )
        count = cursor.fetchone()['cnt']

        if count >= MAX_UPLOADS_PER_USER_PER_HOUR:
            return False, f"Rate limit exceeded. Max {MAX_UPLOADS_PER_USER_PER_HOUR} uploads per hour."

        return True, "OK"

    @staticmethod
    def record_upload(user_id: str, db):
        """Record an upload for rate limiting."""
        db.execute(
            'INSERT INTO upload_rate_limits (user_id, upload_time) VALUES (?, ?)',
            (user_id, datetime.utcnow())
        )
        db.commit()


class TrustScoreManager:
    """Manages user trust scores based on contribution history."""

    @staticmethod
    def get_trust_score(user_id: str, db) -> float:
        cursor = db.execute(
            'SELECT trust_score FROM user_trust_scores WHERE user_id = ?',
            (user_id,)
        )
        row = cursor.fetchone()
        if row:
            return row['trust_score']
        # New user default trust
        db.execute(
            'INSERT OR IGNORE INTO user_trust_scores (user_id, trust_score) VALUES (?, 0.5)',
            (user_id,)
        )
        db.commit()
        return 0.5

    @staticmethod
    def update_trust_score(user_id: str, approved: bool, db):
        """Update trust score based on contribution approval/rejection."""
        cursor = db.execute(
            'SELECT * FROM user_trust_scores WHERE user_id = ?',
            (user_id,)
        )
        row = cursor.fetchone()

        if row:
            total = row['total_contributions'] + 1
            approved_count = row['approved_contributions'] + (1 if approved else 0)
            rejected_count = row['rejected_contributions'] + (0 if approved else 1)
            # Trust score is ratio of approved contributions with smoothing
            trust_score = (approved_count + 1) / (total + 2)  # Laplace smoothing
        else:
            total = 1
            approved_count = 1 if approved else 0
            rejected_count = 0 if approved else 1
            trust_score = (approved_count + 1) / (total + 2)

        db.execute('''
            INSERT INTO user_trust_scores (user_id, trust_score, total_contributions,
                                           approved_contributions, rejected_contributions, last_updated)
            VALUES (?, ?, ?, ?, ?, ?)
            ON CONFLICT(user_id) DO UPDATE SET
                trust_score = ?,
                total_contributions = ?,
                approved_contributions = ?,
                rejected_contributions = ?,
                last_updated = ?
        ''', (user_id, trust_score, total, approved_count, rejected_count, datetime.utcnow(),
              trust_score, total, approved_count, rejected_count, datetime.utcnow()))
        db.commit()


# Initialize components
validator = DataValidator()
rate_limiter = RateLimiter()
trust_manager = TrustScoreManager()


def build_model() -> tf.keras.Model:
    """Build image classification model."""
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=(*IMAGE_SIZE, 1)),
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(64, activation='relu'),
        tf.keras.layers.Dropout(0.3),
        tf.keras.layers.Dense(NUM_CLASSES, activation='softmax')
    ])
    model.compile(
        optimizer='adam',
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )
    return model


def load_or_create_model() -> tf.keras.Model:
    """Load existing model or create new one."""
    if os.path.exists(app.config['MODEL_PATH']):
        try:
            model = tf.keras.models.load_model(app.config['MODEL_PATH'])
            logger.info("Loaded existing model")
            return model
        except Exception as e:
            logger.warning(f"Failed to load model: {e}")
    model = build_model()
    logger.info("Created new model")
    return model


def compute_file_hash(content: bytes) -> str:
    """Compute SHA-256 hash of file content."""
    return hashlib.sha256(content).hexdigest()


