@app.route('/api/upload', methods=['POST'])
def upload_training_data():
    """
    Upload training data (CSV format).
    CSV should have pixel columns and a 'label' column.
    """
    # Authentication (simplified - use proper auth in production)
    user_id = request.headers.get('X-User-ID')
    if not user_id:
        return jsonify({'error': 'Authentication required (X-User-ID header)'}), 401

    # Sanitize user_id
    user_id = secure_filename(user_id)
    if not user_id:
        return jsonify({'error': 'Invalid user ID'}), 400

    db = get_db()

    # Rate limiting
    allowed, msg = rate_limiter.check_rate_limit(user_id, db)
    if not allowed:
        return jsonify({'error': msg}), 429

    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']

    # Validate file
    is_valid, msg = validator.validate_file(file)
    if not is_valid:
        return jsonify({'error': msg}), 400

    filename = secure_filename(file.filename)
    ext = filename.rsplit('.', 1)[-1].lower()

    # Read content and compute hash
    content = file.read()
    file_hash = compute_file_hash(content)
    file.seek(0)

    # Check for duplicate uploads
    cursor = db.execute(
        'SELECT id FROM contributions WHERE file_hash = ?',
        (file_hash,)
    )
    if cursor.fetchone():
        return jsonify({'error': 'Duplicate file already uploaded'}), 409

    if ext == 'csv':
        return _process_csv_upload(content, filename, file_hash, user_id, db)
    else:
        return jsonify({'error': 'Please upload CSV files for batch training data'}), 400


def _process_csv_upload(content: bytes, filename: str, file_hash: str,
                         user_id: str, db) -> tuple:
    """Process CSV file upload with validation."""
    try:
        df = pd.read_csv(io.BytesIO(content))
    except Exception as e:
        return jsonify({'error': f'Failed to parse CSV: {str(e)}'}), 400

    # Validate data
    is_valid, msg, anomaly_score = validator.validate_csv_data(df)
    if not is_valid:
        return jsonify({'error': msg}), 400

    # Determine initial status based on anomaly score and user trust
    trust_score = trust_manager.get_trust_score(user_id, db)

    if anomaly_score > QUARANTINE_THRESHOLD:
        status = 'quarantined'
    elif trust_score > 0.8 and anomaly_score < 0.1 and not CONTRIBUTION_APPROVAL_REQUIRED:
        status = 'approved'
    else:
        status = 'pending'

    # Optional: Check label consistency with existing model
    existing_model = None
    if os.path.exists(app.config['MODEL_PATH']):
        try:
            existing_model = tf.keras.models.load_model(app.config['MODEL_PATH'])
        except Exception:
            pass

    labels = df['label'].values.astype(int)
    feature_cols = [c for c in df.columns if c != 'label']
    features = df[feature_cols].values.astype(np.float32)

    clean_mask, inconsistency_score = validator.validate_label_consistency(
        features, labels, existing_model
    )

    if inconsistency_score > 0.5:
        status = 'quarantined'
        anomaly_score = max(anomaly_score, inconsistency_score)

    # Record contribution
    cursor = db.execute(
        '''INSERT INTO contributions (user_id, filename, file_hash, num_samples, status, anomaly_score)
           VALUES (?, ?, ?, ?, ?, ?)''',
        (user_id, filename, file_hash, len(df), status, anomaly_score)
    )
    contribution_id = cursor.lastrowid

    # Store individual samples
    stored_count = 0
    for i in range(len(df)):
        if not clean_mask[i] and status != 'quarantined':
            # Skip individually suspicious samples but log them
            logger.info(f"Skipping suspicious sample {i} from contribution {contribution_id}")
            continue

        sample_features = features[i]
        sample_label = int(labels[i])
        sample_data = sample_features.tobytes()
        sample_hash = hashlib.sha256(sample_data + str(sample_label).encode()).hexdigest()

        # Check for duplicate samples
        existing = db.execute(
            'SELECT id FROM training_samples WHERE data_hash = ?',
            (sample_hash,)
        ).fetchone()
        if existing:
            continue

        sample_anomaly = 0.0 if clean_mask[i] else anomaly_score

        db.execute(
            '''INSERT INTO training_samples
               (contribution_id, image_data, label, data_hash, is_validated, anomaly_score)
               VALUES (?, ?, ?, ?, ?, ?)''',
            (contribution_id, sample_data, sample_label, sample_hash,
             1 if status == 'approved' else 0, sample_anomaly)
        )
        stored_count += 1

    db.commit()

    # Record upload for rate limiting
    rate_limiter.record_upload(user_id, db)

    return jsonify({
        'message': 'Upload received',
        'contribution_id': contribution_id,
        'status': status,
        'samples_stored': stored_count,
        'samples_skipped': len(df) - stored_count,
        'anomaly_score': round(anomaly_score, 3),
        'note': 'Data will be reviewed before inclusion in training' if status == 'pending'
                else 'Data quarantined for manual review' if status == 'quarantined'
                else 'Data approved for training'
    }), 201


@app.route('/api/upload/image', methods=['POST'])
def upload_single_image():
    """Upload a single labeled image for training."""
    user_id = request.headers.get('X-User-ID')
    if not user_id:
        return jsonify({'error': 'Authentication required'}), 401

    user_id = secure_filename(user_id)
    if not user_id:
        return jsonify({'error': 'Invalid user ID'}), 400

    db = get_db()

    allowed, msg = rate_limiter.check_rate_limit(user_id, db)
    if not allowed:
        return jsonify({'error': msg}), 429

    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400

    label = request.form.get('label')
    if label is None:
        return jsonify({'error': 'Label required'}), 400

    try:
        label = int(label)
    except ValueError:
        return jsonify({'error': 'Label must be an integer'}), 400

    if label < FEATURE_BOUNDS['label_min'] or label > FEATURE_BOUNDS['label_max']:
        return jsonify({'error': f"Label out of range [{FEATURE_BOUNDS['label_min']}, {FEATURE_BOUNDS['label_max']}]"}), 400

    image_file = request.files['image']
    image_data = image_file.read()

    # Validate image
    is_valid, msg = validator.validate_image(image_data)
    if not is_valid:
        return jsonify({'error': msg}), 400

    # Process image to standard format
    try:
        img = Image.open(io.BytesIO(image_data)).convert('L')  # Grayscale
        img = img.resize(IMAGE_SIZE)
        img_array = np.array(img, dtype=np.float32)
        processed_data = img_array.flatten().tobytes()
    except Exception as e:
        return jsonify({'error': f'Image processing failed: {str(e)}'}), 400

    file_hash = compute_file_hash(image_data)
    data_hash = hashlib.sha256(processed_data + str(label).encode()).hexdigest()

    # Check duplicates
    existing = db.execute(
        'SELECT id FROM training_samples WHERE data_hash = ?',
        (data_hash,)
    ).fetchone()
    if existing:
        return jsonify({'error': 'Duplicate sample'}), 409

    trust_score = trust_manager.get_trust_score(user_id, db)
    status = 'approved' if trust_score > 0.8 and not CONTRIBUTION_APPROVAL_REQUIRED else 'pending'

    cursor = db.execute(
        '''INSERT INTO contributions (user_id, filename, file_hash, num_samples, status, anomaly_score)
           VALUES (?, ?, ?, 1, ?, 0.0)''',
        (user_id, secure_filename(image_file.filename), file_hash, status)
    )
    contribution_id = cursor.lastrowid

    db.execute(
        '''INSERT INTO training_samples
           (contribution_id, image_data, label, data_hash, is_validated, anomaly_score)
           VALUES (?, ?, ?, ?, ?, 0.0)''',
        (contribution_id, processed_data, label, data_hash,
         1 if status == 'approved' else 0)
    )

    db.commit()
    rate_limiter.record_upload(user_id, db)

    return jsonify({
        'message': 'Image uploaded',
        'contribution_id': contribution_id,
        'status': status,
    }), 201


@app.route('/api/admin/review', methods=['GET'])
def list_pending_contributions():
    """List contributions pending review (admin only)."""
    admin_key = request.headers.get('X-Admin-Key')
    if admin_key != os.environ.get('ADMIN_KEY', 'change-me-in-production'):
        return jsonify({'error': 'Unauthorized'}), 403

    db = get_db()
    status_filter = request.args.get('status', 'pending')

    cursor = db.execute(
        '''SELECT c.*, u.trust_score
           FROM contributions c
           LEFT JOIN user_trust_scores u ON c.user_id = u.user_id
           WHERE c.status = ?
           ORDER BY c.anomaly_score DESC, c.upload_time ASC
           LIMIT 50''',
        (status_filter,)
    )

    contributions = []
    for row in cursor.fetchall():
        contributions.append({
            'id': row['id'],
            'user_id': row['user_id'],
            'filename': row['filename'],
            'num_samples': row['num_samples'],
            'anomaly_score': row['anomaly_score'],
            'upload_time': row['upload_time'],
            'trust_score': row['trust_score'],
        })

    return jsonify({'contributions': contributions})


@app.route('/api/admin/review/<int:contribution_id>', methods=['POST'])
def review_contribution(contribution_id):
    """Approve or reject a contribution (admin only)."""
    admin_key = request.headers.get('X-Admin-Key')
    if admin_key != os.environ.get('ADMIN_KEY', 'change-me-in-production'):
        return jsonify({'error': 'Unauthorized'}), 403

    data = request.get_json()
    if not data or 'action' not in data:
        return jsonify({'error': 'Action required (approve/reject)'}), 400

    action = data['action']
    if action not in ('approve', 'reject'):
        return jsonify({'error': 'Action must be approve or reject'}), 400

    reviewer_id = request.headers.get('X-User-ID', 'admin')
    notes = data.get('notes', '')

    db = get_db()

    contribution = db.execute(
        'SELECT * FROM contributions WHERE id = ?',
        (contribution_id,)
    ).fetchone()

    if not contribution:
        return jsonify({'error': 'Contribution not found'}), 404

    new_status = 'approved' if action == 'approve' else 'rejected'

    db.execute(
        '''UPDATE contributions
           SET status = ?, review_notes = ?, reviewer_id = ?, review_time = ?
           WHERE id = ?''',
        (new_status, notes, reviewer_id, datetime.utcnow(), contribution_id)
    )

    if action == 'approve':
        db.execute(
            'UPDATE training_samples SET is_validated = 1 WHERE contribution_id = ?',
            (contribution_id,)
        )
    else:
        # Remove rejected samples
        db.execute(
            'DELETE FROM training_samples WHERE contribution_id = ?',
            (contribution_id,)
        )

    # Update user trust score
    trust_manager.update_trust_score(contribution['user_id'], action == 'approve', db)

    db.commit()

    return jsonify({
        'message': f'Contribution {contribution_id} {new_status}',
        'contribution_id': contribution_id,
        'status': new_status,
    })


@app.route('/api/train', methods=['POST'])
def train_model():
    """
    Trigger model training using only approved/validated data.
    Admin only endpoint.
    """
    admin_key = request.headers.get('X-Admin-Key')
    if admin_key != os.environ.get('ADMIN_KEY', 'change-me-in-production'):
        return jsonify({'error': 'Unauthorized'}), 403

    db = get_db()

    # Only use validated samples from approved contributions
    cursor = db.execute(
        '''SELECT ts.image_data, ts.label
           FROM training_samples ts
           JOIN contributions c ON ts.contribution_id = c.id
           WHERE ts.is_validated = 1 AND c.status = 'approved'
           ORDER BY c.upload_time'''
    )

    rows = cursor.fetchall()

    if len(rows) < MIN_APPROVED_SAMPLES_FOR_TRAINING:
        return jsonify({
            'error': f'Not enough approved samples. Have {len(rows)}, need {MIN_APPROVED_SAMPLES_FOR_TRAINING}'
        }), 400

    # Prepare training data
    images = []
    labels = []

    for row in rows:
        img_data = np.frombuffer(row['image_data'], dtype=np.float32)
        expected_size = IMAGE_SIZE[0] * IMAGE_SIZE[1]

        if len(img_data) == expected_size:
            img = img_data.reshape(IMAGE_SIZE[0], IMAGE_SIZE[1], 1)
        else:
            # Try to reshape from flat pixel data
            side = int(np.sqrt(len(img_data)))
            if side * side == len(img_data):
                img = img_data.reshape(side, side, 1)
                img = tf.image.resize(img, IMAGE_SIZE).numpy()
            else:
                logger.warning(f"Skipping sample with unexpected size: {len(img_data)}")
                continue

        images.append(img)
        labels.append(row['label'])

    if len(images) == 0:
        return jsonify({'error': 'No valid training samples after processing'}), 400

    images = np.array(images, dtype=np.float32) / 255.0
    labels = np.array(labels, dtype=np.int32)

    # Final validation: check class balance
    class_counts = np.bincount(labels, minlength=NUM_CLASSES)
    total = len(labels)
    max_class_ratio = np.max(class_counts) / total

    if max_class_ratio > 0.8:
        logger.warning(f"Highly imbalanced training data. Max class ratio: {max_class_ratio:.2f}")
        # Apply class weights to mitigate
        class_weights = {}
        for i in range(NUM_CLASSES):
            if class_counts[i] > 0:
                class_weights[i] = total / (NUM_CLASSES * class_counts[i])
            else:
                class_weights[i] = 1.0
    else:
        class_weights = None

    # Split into train/validation
    indices = np.random.permutation(len(images))
    split = int(0.8 * len(indices))
    train_idx, val_idx = indices[:split], indices[split:]

    x_train, y_train = images[train_idx], labels[train_idx]
    x_val, y_val = images[val_idx], labels[val_idx]

    # Load or create model
    model = load_or_create_model()

    # Save current model as backup before training
    backup_path = app.config['MODEL_PATH'] + '.backup'
    if os.path.exists(app.config['MODEL_PATH']):
        model.save(backup_path)

    # Train with early stopping to prevent overfitting on potentially noisy data
    callbacks = [
        tf.keras.callbacks.EarlyStopping(
            monitor='val_accuracy',
            patience=5,
            restore_best_weights=True
        ),
    ]

    epochs = int(request.get_json().get('epochs', 20)) if request.get_json() else 20
    epochs = min(epochs, 100)  # Cap epochs

    history = model.fit(
        x_train, y_train,
        validation_data=(x_val, y_val),
        epochs=epochs,
        batch_size=32,
        callbacks=callbacks,
        class_weight=class_weights,
        verbose=1
    )

    # Evaluate
    val_loss, val_accuracy = model.evaluate(x_val, y_val, verbose=0)

    # Rollback if accuracy degraded significantly
    if os.path.exists(backup_path):
        try:
            old_model = tf.keras.models.load_model(backup_path)
            old_loss, old_accuracy = old_model.evaluate(x_val, y_val, verbose=0)

            if val_accuracy < old_accuracy - 0.05:  # More than 5% accuracy drop
                logger.warning(
                    f"Model accuracy degraded from {old_accuracy:.4f} to {val_accuracy:.4f}. "
                    f"Rolling back."
                )
                model = old_model
                val_accuracy = old_accuracy
                val_loss = old_loss
        except Exception as e:
            logger.warning(f"Could not evaluate backup model: {e}")

    # Save model
    model.save(app.config['MODEL_PATH'])

    # Compute model hash for versioning
    with open(app.config['MODEL_PATH'], 'rb') as f:
        model_hash = hashlib.sha256(f.read()).hexdigest()

    # Record model version
    version = datetime.utcnow().strftime('%Y%m%d_%H%M%S')
    db.execute(
        '''INSERT INTO model_versions (version, num_training_samples, accuracy, model_hash)
           VALUES (?, ?, ?, ?)''',
        (version, len(images), float(val_accuracy), model_hash)
    )
    db.commit()

    # Update reference stats for future anomaly detection
    validator.save_reference_stats(
        (images * 255).reshape(len(images), -1).astype(np.float32),
        labels
    )

    return jsonify({
        'message': 'Training complete',
        'version': version,
        'num_training_samples': len(images),
        'num_validation_samples': len(x_val),
        'validation_accuracy': round(float(val_accuracy), 4),
        'validation_loss': round(float(val_loss), 4),
        'class_distribution': {str(i): int(c) for i, c in enumerate(class_counts)},
        'model_hash': model_hash,
    })


@app.route('/api/predict', methods=['POST'])
def predict():
    """Make predictions using the trained model."""
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400

    image_file = request.files['image']
    image_data = image_file.read()

    is_valid, msg = validator.validate_image(image_data)
    if not is_valid:
        return jsonify({'error': msg}), 400

    try:
        img = Image.open(io.BytesIO(image_data)).convert('L')
        img = img.resize(IMAGE_SIZE)
        img_array = np.array(img, dtype=np.float32) / 255.0
        img_array = img_array.reshape(1, *IMAGE_SIZE, 1)
    except Exception as e:
        return jsonify({'error': f'Image processing failed: {str(e)}'}), 400

    model = load_or_create_model()
    predictions = model.predict(img_array, verbose=0)

    predicted_class = int(np.argmax(predictions[0]))
    confidence = float(np.max(predictions[0]))

    return jsonify({
        'predicted_class': predicted_class,
        'confidence': round(confidence, 4),
        'all_probabilities': {str(i): round(float(p), 4) for i, p in enumerate(predictions[0])},
    })


@app.route('/api/stats', methods=['GET'])
def get_stats():
    """Get training data and model statistics."""
    db = get_db()

    total_contributions = db.execute('SELECT COUNT(*) as cnt FROM contributions').fetchone()['cnt']
    approved = db.execute("SELECT COUNT(*) as cnt FROM contributions WHERE status='approved'").fetchone()['cnt']
    pending = db.execute("SELECT COUNT(*) as cnt FROM contributions WHERE status='pending'").fetchone()['cnt']
    quarantined = db.execute("SELECT COUNT(*) as cnt FROM contributions WHERE status='quarantined'").fetchone()['cnt']
    rejected = db.execute("SELECT COUNT(*) as cnt FROM contributions WHERE status='rejected'").fetchone()['cnt']

    total_samples = db.execute(
        "SELECT COUNT(*) as cnt FROM training_samples WHERE is_validated=1"
    ).fetchone()['cnt']

    latest_model = db.execute(
        'SELECT * FROM model_versions ORDER BY created_at DESC LIMIT 1'
    ).fetchone()

    return jsonify({
        'contributions': {
            'total': total_contributions,
            'approved': approved,
            'pending': pending,
            'quarantined': quarantined,
            'rejected': rejected,
        },
        'validated_samples': total_samples,
        'latest_model': {
            'version': latest_model['version'] if latest_model else None,
            'accuracy': latest_model['accuracy'] if latest_model else None,
            'training_samples': latest_model['num_training_samples'] if latest_model else None,
        } if latest_model else None,
    })


